-- 7_generated_ads.sql - Generated ads for library history&#10;&#10;-- Enable UUID extension&#10;CREATE EXTENSION IF NOT EXISTS "uuid-ossp";&#10;&#10;CREATE TABLE IF NOT EXISTS generated_ads (&#10;  id                          UUID PRIMARY KEY DEFAULT uuid_generate_v4(),&#10;  campaign_id                 UUID REFERENCES campaigns(id) ON DELETE SET NULL,&#10;  user_id                     UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,&#10;  product_name                VARCHAR(255) NOT NULL,&#10;  product_description         TEXT,&#10;  target_audience             VARCHAR(500),&#10;  tone                        VARCHAR(50),&#10;  language                    VARCHAR(10) DEFAULT &#39;en&#39;,&#10;  script_text                 TEXT NOT NULL,&#10;  word_count                  INTEGER DEFAULT 0,&#10;  estimated_duration_seconds  INTEGER DEFAULT 0,&#10;  status                      VARCHAR(50) DEFAULT &#39;draft&#39;,&#10;  created_at                  TIMESTAMP DEFAULT CURRENT_TIMESTAMP,&#10;  updated_at                  TIMESTAMP DEFAULT CURRENT_TIMESTAMP&#10;);&#10;&#10;-- Indexes&#10;CREATE INDEX CONCURRENTLY IF NOT EXISTS idx_generated_ads_user_id ON generated_ads(user_id);&#10;CREATE INDEX CONCURRENTLY IF NOT EXISTS idx_generated_ads_status ON generated_ads(status);&#10;CREATE INDEX CONCURRENTLY IF NOT EXISTS idx_generated_ads_created_at ON generated_ads(created_at DESC);
